mapper.insert:
insert into `ai_runtime_config` (
    config_key, enabled, provider, base_url, chat_path, api_key_ciphertext, model, temperature, top_k,
    fallback_enabled, cache_ttl_seconds, connect_timeout_ms, read_timeout_ms, created_at, updated_at
) values (
    #{configKey}, #{enabled}, #{provider}, #{baseUrl}, #{chatPath}, #{apiKeyCiphertext}, #{model}, #{temperature}, #{topK},
    #{fallbackEnabled}, #{cacheTtlSeconds}, #{connectTimeoutMs}, #{readTimeoutMs}, #{createdAt}, #{updatedAt}
)
